VALUES
  ('dietitian-moex-04454', 'dietitian', 'dietitian-moex-113-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關重大燒燙傷後水分補充的方式及量，下列敘述何者錯誤？', '["輸液復甦（fluid resuscitation）需在燒燙傷後24～48小時內立即進行", "輸液復甦給予的量為2～4 mL/kg bw/% 總燒傷面積（total body surface area, TBSA），且在燒傷後12小 時內需灌輸計算總量的一半", "輸液復甦完成後水分補充仍要足夠，由傷口流失的水分亦需補充，其計算公式為2～3.1 mL/kg bw/% TBSA/day", "需要監測血中鈉離子含量、滲透壓之改變及體重變化來觀察液體補充之狀態"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:35+00:00", "source_pdf_sha1": "4a5f2c07c6ff", "answer_pdf_sha1": "ca5cb7bf2305", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04455', 'dietitian', 'dietitian-moex-113-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '當病人進行腹腔手術或是有腸道瘻管時，下列對於手術後之併發症及營養照顧敘述何者錯誤？', '["腹腔手術後常有腹部腔室症候群（abdominal compartment syndrome），為腹腔內壓增加而造成腹腔內的 器官缺血", "計算腹腔手術後病人蛋白質攝取量時，需考慮腹腔引流液所造成的蛋白質流失，每流失1公升的引流液需額 外給予15～30公克的蛋白質", "對腹腔手術後病人如處於穩定時期，不需要額外補充灌輸液或是增壓劑，可給予腸道營養支持", "如腸道瘻管液體流出超過500毫升／天時，則需要立即使用腸道營養支持方式補充營養素"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:35+00:00", "source_pdf_sha1": "4a5f2c07c6ff", "answer_pdf_sha1": "ca5cb7bf2305", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04456', 'dietitian', 'dietitian-moex-113-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '目前重症病人營養治療目標，最不需要考慮下列何者？', '["attenuate the metabolic response to stress", "increase body weight", "modulate immune response", "prevent oxidative cellular injury"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:35+00:00", "source_pdf_sha1": "4a5f2c07c6ff", "answer_pdf_sha1": "ca5cb7bf2305", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04457', 'dietitian', 'dietitian-moex-113-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '單純飢餓與高生理壓力下之代謝比較，下列那一項最不常見？', '["壓力下呼吸商（respiratory quotient, RQ）較低", "飢餓下常會產生酮體（ketone body）", "壓力下有較高的糖質新生作用及基礎能量消耗（BEE）", "壓力下有較高的骨骼肌蛋白質分解及負氮平衡"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:35+00:00", "source_pdf_sha1": "4a5f2c07c6ff", "answer_pdf_sha1": "ca5cb7bf2305", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04458', 'dietitian', 'dietitian-moex-113-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關營養不良對肺部系統的影響，下列敘述何者不適當？', '["蛋白質和鐵缺乏會使血液hemoglobin濃度下降，影響紅血球攜氧能力", "當細胞內鈣、鎂、磷和鉀濃度過低時會影響呼吸肌的功能", "hypoalbuminemia 會使血漿中膠質滲透壓下降，可能引發肺水腫", "肺病病人需注意膠原蛋白的足夠攝取，以強化肺部的結締組織"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:35+00:00", "source_pdf_sha1": "4a5f2c07c6ff", "answer_pdf_sha1": "ca5cb7bf2305", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04459', 'dietitian', 'dietitian-moex-113-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '慢性阻塞性肺病（COPD）病人容易罹患骨質疏鬆症（osteoporosis）的可能原因，下列何者較無關？', '["抽菸", "自體免疫疾病", "類固醇的使用", "維生素D缺乏"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:35+00:00", "source_pdf_sha1": "4a5f2c07c6ff", "answer_pdf_sha1": "ca5cb7bf2305", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04460', 'dietitian', 'dietitian-moex-113-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '接受化療藥物的病人，當發生噁心和嘔吐時，其飲食相關建議下列何者正確？', '["進食後，頭部位置要抬高30分鐘", "增加高濃度食物，以提高熱量攝取", "飯前散步促進腸胃道蠕動", "供應含有液體或醬汁的食物"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:35+00:00", "source_pdf_sha1": "4a5f2c07c6ff", "answer_pdf_sha1": "ca5cb7bf2305", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
