  ('dietitian-moex-04462', 'dietitian', 'dietitian-moex-113-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '營養評估時需獲得病人之營養相關背景資料（nutrition-related history data）包括那些？①攝食量　②', '["①②③④⑤⑥", "僅①②④⑤⑥", "僅①②③⑥", "僅①②④⑤"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:35+00:00", "source_pdf_sha1": "4a5f2c07c6ff", "answer_pdf_sha1": "ca5cb7bf2305", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04463', 'dietitian', 'dietitian-moex-113-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '阿茲海默症（Alzheimer Disease）病人進展至那一階段時會出現無法順利咀嚼並吞嚥食物的問題？', '["amnesia", "aphasia", "apraxia", "anorexia"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:35+00:00", "source_pdf_sha1": "4a5f2c07c6ff", "answer_pdf_sha1": "ca5cb7bf2305", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "101", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
